// ===== State =====
let currentPeriod = 'full', currentView = 'netflow', topN = 15;
// coloring mode: 'category' (by major category) or 'role' (classification from analysis)
let colorMode = 'category';
// flow animation state
let flowAnim = true, flowSpeed = 1, flowDensity = 3;
// analysis map loaded from data/processed/Discipline_Mobility_Analysis.json
let ANALYSIS_MAP = {};
const roleColorMap = {
  'output-dominant': '#e74c3c',
  'input-dominant': '#3498db',
  'bridge': '#f39c12',
  'isolated': '#9aa0a6',
  'balanced': '#2ecc71',
  'unknown': '#999999'
};

// ===== Init =====
(async function() {
  // 优先尝试加载处理后的 JSON 数据（不覆盖原始文件）
  try {
    const resp = await fetch('data/processed/Discipline_Mobility_Network.json');
    if (resp.ok) {
      const j = await resp.json();
      if (j && j.periods) {
        FULLDATA = j; // 使用处理后的数据
        console.log('Loaded processed data: data/processed/Discipline_Mobility_Network.json');
      }
    } else {
      console.log('Processed JSON not found; using embedded data');
    }
  } catch (e) {
    console.warn('Error loading processed JSON — using embedded data', e);
  }
  // 尝试加载分析结果（脚本生成的分类/中心性结果）
  try {
    const aresp = await fetch('data/processed/Discipline_Mobility_Analysis.json');
    if (aresp.ok) {
      const aj = await aresp.json();
      if (aj && aj.analysis) {
        aj.analysis.forEach(x => { ANALYSIS_MAP[x.name] = x; });
        console.log('Loaded analysis data: data/processed/Discipline_Mobility_Analysis.json');
      }
    }
  } catch (e) {
    console.warn('No analysis JSON found or error parsing it', e);
  }
  const c = document.getElementById('periodBtns');
  Object.keys(FULLDATA.periods).forEach((k, i) => {
    const b = document.createElement('button');
    b.className = 'btn' + (i ? '' : ' active');
    b.textContent = FULLDATA.periods[k].l;
    b.dataset.period = k;
    b.onclick = () => { c.querySelectorAll('.btn').forEach(x => x.classList.remove('active')); b.classList.add('active'); currentPeriod = k; render(); };
    c.appendChild(b);
  });
  document.querySelectorAll('.view-btn').forEach(b => {
    b.onclick = () => { document.querySelectorAll('.view-btn').forEach(x => x.classList.remove('active')); b.classList.add('active'); currentView = b.dataset.view; render(); };
  });
  // color mode buttons removed from UI; default coloring remains (按大类)
  // focus buttons for Sankey/river charts
  const focusGroup = document.getElementById('focusBtns');
  if (focusGroup) {
    focusGroup.querySelectorAll('.focus-btn').forEach(b => {
      b.onclick = () => { focusGroup.querySelectorAll('.focus-btn').forEach(x => x.classList.remove('active')); b.classList.add('active'); renderFocusSankey(b.dataset.focus); };
    });
  }
  // search and topN controls removed
  // flow animation controls
  const flowToggle = document.getElementById('flowAnimToggle');
  const flowSpeedInput = document.getElementById('flowSpeed');
  const flowDensityInput = document.getElementById('flowDensity');
  if (flowToggle) {
    flowAnim = !!flowToggle.checked;
    flowToggle.addEventListener('change', () => { flowAnim = !!flowToggle.checked; if (!flowAnim && window._flowTimer) { try{ window._flowTimer.stop(); }catch(e){} } render(); });
  }
  if (flowSpeedInput) {
    flowSpeedInput.value = flowSpeed;
    flowSpeedInput.addEventListener('input', () => { flowSpeed = +flowSpeedInput.value; });
  }
  if (flowDensityInput) {
    flowDensityInput.value = flowDensity;
    flowDensityInput.addEventListener('input', () => { flowDensity = +flowDensityInput.value; render(); });
  }
  render();
})();
// topN slider and search removed

function getFilteredIndices(raw) {
  // filtering disabled — return all indices in original order
  return raw.d.map((_, i) => i);
}

// ===== Slice data =====
function slicedData() {
  const raw = FULLDATA.periods[currentPeriod];
  const filtered = getFilteredIndices(raw);
  const n = Math.min(topN, filtered.length);
  const idx = filtered.slice(0, n);
  const d = idx.map(i => raw.d[i]);
  const m = idx.map(i => idx.map(j => (raw.m[i] && raw.m[i][j]) ? raw.m[i][j] : 0));
  // merge analysis info (role, pagerank, community) when available
  d.forEach(dd => {
    const a = ANALYSIS_MAP[dd.n];
    if (a) {
      dd.role = a.role || 'unknown';
      dd.pagerank = a.pagerank || 0;
      dd.community = a.community || -1;
    } else {
      dd.role = 'unknown';
    }
  });
  return { l: raw.l, d, m, n, _filteredTotal: filtered.length, _rawTotal: raw.d.length };
}

// ===== Render =====
function render() {
  // Use full (un-sliced) data for the selected period and merge analysis info
  const raw = FULLDATA.periods[currentPeriod];
  const data = { l: raw.l, d: (raw.d || []).map(dd => Object.assign({}, dd)), m: raw.m, n: (raw.d || []).length };
  data.d.forEach(dd => {
    const a = ANALYSIS_MAP[dd.n];
    if (a) {
      dd.role = a.role || 'unknown';
      dd.pagerank = a.pagerank || 0;
      dd.community = a.community || -1;
    } else {
      dd.role = 'unknown';
    }
  });
  const container = document.getElementById('chartArea');
  container.innerHTML = '';
  // Build legend according to current colorMode
  const leg = document.getElementById('legend');
  if (leg) {
    leg.style.display = 'block';
    leg.innerHTML = '';
    if (colorMode === 'role') {
      const wrap = document.createElement('div');
      wrap.className = 'legend-roles';
      Object.keys(roleColorMap).forEach(k => {
        const it = document.createElement('div'); it.className = 'legend-item';
        const sw = document.createElement('span'); sw.className = 'swatch'; sw.style.background = roleColorMap[k];
        const lbl = document.createElement('span'); lbl.className = 'lbl'; lbl.textContent = k.replace(/-/g, ' ');
        it.appendChild(sw); it.appendChild(lbl); wrap.appendChild(it);
      });
      leg.appendChild(wrap);
    } else {
      // category legend from FULLDATA.cats
      const catMap = Object.fromEntries(FULLDATA.cats || []);
      const wrap = document.createElement('div'); wrap.className = 'legend-cats';
      Object.keys(catMap).forEach(k => {
        const it = document.createElement('div'); it.className = 'legend-item';
        const sw = document.createElement('span'); sw.className = 'swatch'; sw.style.background = catMap[k];
        const lbl = document.createElement('span'); lbl.className = 'lbl'; lbl.textContent = k;
        it.appendChild(sw); it.appendChild(lbl); wrap.appendChild(it);
      });
      leg.appendChild(wrap);
    }
  }
  const total = data.d.reduce((s, d) => s + d.o, 0);
  // totalFlow excluding discipline self-citations (diagonal entries)
  let totalFlow = 0;
  for (let i = 0; i < data.n; i++) for (let j = 0; j < data.n; j++) {
    if (i === j) continue;
    const v = (data.m[i] && data.m[i][j]) ? data.m[i][j] : 0;
    totalFlow += v;
  }
  document.getElementById('statsBar').innerHTML = `
    <div class="stat-item"><div class="stat-value">${data.n}</div><div class="stat-label">学科数</div></div>
    <div class="stat-item"><div class="stat-value">${(total/1000).toFixed(0)}k</div><div class="stat-label">总流出次数</div></div>
    <div class="stat-item"><div class="stat-value">${(totalFlow/1000000).toFixed(1)}M</div><div class="stat-label">总流动量</div></div>`;

  if (!data.n) {
    container.innerHTML = `<div class="empty-hint">未找到匹配的学科，请调整筛选关键词</div>`;
    return;
  }

  switch (currentView) {
    case 'chord': renderChord(data, container); break;
    case 'netflow': renderNetFlow(data, container); break;
    case 'network': renderNetwork(FULLDATA.periods[currentPeriod], container); break;
    case 'heatmap': renderHeatmap(data, container); break;
    case 'openness': renderOpenness(data, container); break;
    case 'retention': renderRetention(data, container); break;
    case 'diff_heatmap': renderDiffHeatmap(data, container); break;
    case 'role_sankey':
      // render role-category sankey into the same chart container
      if (typeof renderRoleSankey === 'function') renderRoleSankey();
      break;
  }
  // insight panel removed
}

// ===== Tooltip =====
const tt = document.getElementById('tooltip');
function showTT(x, y, h) { tt.style.left = Math.min(x + 10, window.innerWidth - 310) + 'px'; tt.style.top = (y - 10) + 'px'; tt.innerHTML = h; tt.classList.add('show'); }
function hideTT() { tt.classList.remove('show'); }

// Helper: pick color for a discipline object (may have .n, .c, .role)
function colorForNodeObj(d) {
  if (!d) return '#999';
  const role = d.role || (ANALYSIS_MAP[d.n] && ANALYSIS_MAP[d.n].role);
  if (colorMode === 'role') return roleColorMap[role] || roleColorMap.unknown;
  const catMap = Object.fromEntries(FULLDATA.cats || []);
  return catMap[d.c] || '#999';
}

// Search and filter controls removed

// insight panel removed

// Chord diagram view removed — renderChord was intentionally omitted.

// ===== 3. NET FLOW BALANCE (净流动平衡) =====
function renderNetFlow(data, container) {
  // Use full data for current period and aggregate by 学科大类 (category).
  const raw = FULLDATA.periods[currentPeriod];
  const discAll = raw.d || [];
  // Keep the full 11-category taxonomy so zero-valued categories still render.
  const categories = (FULLDATA.cats || []).map(([name]) => name);
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));
  const k = categories.length;

  // sum o/i per category excluding discipline self-citation (s)
  const catStats = categories.map(() => ({ o: 0, i: 0, s: 0 }));
  for (let i = 0; i < discAll.length; i++) {
    const c = discAll[i].c || 'Other';
    const idx = catIndex[c];
    const self = discAll[i].s || 0;
    catStats[idx].o += (discAll[i].o || 0) - self;
    catStats[idx].i += (discAll[i].i || 0) - self;
    // category-level self set to 0 because discipline self-citations removed
    catStats[idx].s += 0;
  }

  const items = categories.map((c, idx) => ({ n: c, c: c, o: catStats[idx].o, i: catStats[idx].i, s: catStats[idx].s, net: (catStats[idx].i || 0) - (catStats[idx].o || 0) }));
  items.sort((a, b) => b.net - a.net);

  const n = items.length;
  const width = Math.max(980, container.clientWidth || 980);
  const margin = { top: 80, right: 40, bottom: 24, left: 320 };
  const barH = Math.max(18, Math.min(40, (600 - margin.top - margin.bottom) / n));
  const height = n * barH + margin.top + margin.bottom + 50;
  const midX = width / 2 + 50;
  const maxAbs = d3.max(items, d => Math.abs(d.net)) || 1;
  const xScale = d3.scaleSqrt().domain([0, maxAbs]).range([0, Math.max(0, width / 2 - margin.left - 60)]);
  const svg = d3.select(container).append('svg').attr('width', width).attr('height', height);
  const g = svg.append('g').attr('transform', `translate(${margin.left},${margin.top})`);
  g.append('line').attr('x1', midX - margin.left).attr('x2', midX - margin.left).attr('y1', -8).attr('y2', n * barH + 4).attr('stroke', '#ccc').attr('stroke-width', 1).attr('stroke-dasharray', '4,3');
  items.forEach((d, i) => {
    const y = i * barH, absv = Math.abs(d.net), barW = xScale(absv);
    if (d.net < 0) g.append('rect').attr('x', midX - margin.left - barW).attr('y', y + 1).attr('width', barW).attr('height', barH - 2).attr('fill', '#e74c3c').attr('opacity', 0.75).attr('rx', 2);
    if (d.net > 0) g.append('rect').attr('x', midX - margin.left).attr('y', y + 1).attr('width', barW).attr('height', barH - 2).attr('fill', '#3498db').attr('opacity', 0.75).attr('rx', 2);
    g.append('rect').attr('x', midX - margin.left - 6).attr('y', y + 1).attr('width', 6).attr('height', barH - 2).attr('fill', d.net < 0 ? '#c0392b' : d.net > 0 ? '#2980b9' : '#ccc').attr('rx', 2);
    const txtX = d.net >= 0 ? midX - margin.left + barW + 4 : midX - margin.left - barW - 4;
    g.append('text').attr('x', txtX).attr('y', y + barH / 2).attr('dy', '0.32em').attr('text-anchor', d.net >= 0 ? 'start' : 'end').attr('font-size', '11px').attr('fill', '#555')
      .text(d.net ? (d.net > 0 ? '+' : '') + d.net.toLocaleString() : '0');
  });
  g.selectAll('.lbl').data(items).join('text')
    .attr('x', -30).attr('y', (d, i) => i * barH + barH / 2).attr('dy', '0.32em').attr('text-anchor', 'end').attr('font-size', '12px').attr('fill', '#333')
    .text(d => d.n);
  g.selectAll('.cd').data(items).join('circle').attr('cx', -18).attr('cy', (d, i) => i * barH + barH / 2).attr('r', 5).attr('fill', d => colorForNodeObj(d));
  svg.append('text').attr('x', midX - margin.left - 12).attr('y', 40).attr('text-anchor', 'end').attr('font-size', '12px').attr('fill', '#e74c3c').attr('font-weight', '600').text('净流出（送出人才）');
  svg.append('text').attr('x', midX - margin.left + 12).attr('y', 40).attr('text-anchor', 'start').attr('font-size', '12px').attr('fill', '#3498db').attr('font-weight', '600').text('净流入（吸纳人才）');
}

// ===== 学科开放度视图 =====
function renderOpenness(data, container) {
  container.innerHTML = '';
  const disc = (data.d || []).map(d => Object.assign({}, d));
  // openness = (o - s) / (o + i - s)
  disc.forEach(d => {
    const o = d.o || 0, i = d.i || 0, s = d.s || 0;
    const denom = Math.max(1, o + i - s);
    d.open = (o - s) / denom;
  });
  disc.sort((a, b) => b.open - a.open);
  const top = disc.slice(0, Math.min(10, disc.length));

  const width = Math.max(900, container.clientWidth || 900);
  const barH = 32;
  const maxOpen = d3.max(top, d => Math.abs(d.open)) || 1;
  const widthPad = 40;
  const svgWidth = Math.max(900, container.clientWidth || 900);
  const barAreaW = svgWidth - widthPad*2;
  const barsH = top.length * barH + 40;
  const radius = Math.min(180, Math.floor((svgWidth - 160) / 4));
  const donutCenterY = barsH + radius + 30;
  const svgHeight = donutCenterY + radius + 80;
  const svg = d3.select(container).append('svg').attr('width', svgWidth).attr('height', svgHeight);

  // Top: bars (full-width)
  const leftG = svg.append('g').attr('transform', `translate(${widthPad+180},20)`);
  const maxBarWidth = Math.max(120, Math.min(520, barAreaW - 260));
  const x = d3.scaleLinear().domain([0, maxOpen]).range([0, maxBarWidth]);
  const barColor = '#4f6db6';
  leftG.selectAll('rect').data(top).join('rect')
    .attr('x', 180).attr('y', (d,i) => i*barH)
    .attr('height', barH-6).attr('width', d => x(d.open))
    .attr('fill', barColor).attr('opacity', 0.95);
  leftG.selectAll('text.name').data(top).join('text').attr('class','name')
  .attr('x', 175)                   // 改为 175（接近水平条起始位置 180）
  .attr('y', (d,i) => i*barH + (barH/2))
  .attr('dy','0.32em')
  .attr('text-anchor', 'end')       // 关键：设置文本锚点为右对齐
  .attr('font-size','12px')
  .text(d => d.n);
  leftG.selectAll('text.val').data(top).join('text').attr('class','val')
    .attr('x', d => 180 + x(d.open) + 8).attr('y', (d,i) => i*barH + (barH/2)).attr('dy','0.32em').attr('font-size','12px').text(d => (d.open*100).toFixed(1)+'%');
  leftG.append('text').attr('x', 10).attr('y', -6).attr('font-size','13px').attr('font-weight','700').text('按开放度排序（前10）');

  // Donut below bars: category average openness
  const categories = Array.from(new Set(disc.map(d => d.c || 'Other')));
  const catStats = categories.map(c => ({ c, vals: [] }));
  const idx = Object.fromEntries(categories.map((c,i)=>[c,i]));
  disc.forEach(d => { const k = idx[d.c || 'Other']; if (k!==undefined) catStats[k].vals.push(d.open); });
  const catAgg = catStats.map(cs => ({ c: cs.c, open: cs.vals.length ? (d3.mean(cs.vals)) : 0 }));
  // ensure every category has a visible slice (add small floor to value)
  const pie = d3.pie().value(d => Math.max(0.0001, Math.abs(d.open))).sort(null);
  const arc = d3.arc().innerRadius(radius*0.5).outerRadius(radius);
  const rightG = svg.append('g').attr('transform', `translate(${svgWidth/2},${donutCenterY})`);
  const arcs = rightG.selectAll('.arc').data(pie(catAgg)).join('g').attr('class','arc');
  arcs.append('path')
    .attr('d', arc)
    .attr('fill', d => colorForNodeObj({ c: d.data.c }))
    .attr('stroke','#fff')
    .attr('stroke-width',0.5)
    .style('cursor', 'pointer')
    .on('mouseenter', function(ev, d) {
      d3.select(this).attr('stroke-width', 1.5);
      showTT(ev.pageX, ev.pageY, `<div class="tt-title">${d.data.c}</div><div class="tt-row"><span>开放度</span><span>${(d.data.open * 100).toFixed(1)}%</span></div>`);
    })
    .on('mousemove', function(ev, d) {
      showTT(ev.pageX, ev.pageY, `<div class="tt-title">${d.data.c}</div><div class="tt-row"><span>开放度</span><span>${(d.data.open * 100).toFixed(1)}%</span></div>`);
    })
    .on('mouseleave', function() {
      d3.select(this).attr('stroke-width', 0.5);
      hideTT();
    });
  arcs.append('title').text(d => `${d.data.c}: ${ (d.data.open*100).toFixed(1) }%`);

  // Legend under donut: category and avg value
  const legX = widthPad + 10;
  const legY = donutCenterY + radius + 24;
  const leg = svg.append('g').attr('transform', `translate(${legX},${legY})`);
  // Legend: larger swatches, single entry per major category, two-column grid
  // Adaptive legend columns so entries won't be clipped
  const approxColWidth = 260;
  const cols = Math.max(1, Math.min(4, Math.floor((svgWidth - widthPad*2) / approxColWidth)));
  const rows = Math.ceil(catAgg.length / cols);
  // increase svg height to accommodate legend if necessary
  const extraLegH = rows * 22 + 24;
  const finalSvgH = svgHeight + extraLegH;
  svg.attr('height', finalSvgH);
  leg.attr('transform', `translate(${widthPad + 10},${donutCenterY + radius + 18})`);
  leg.selectAll('g').data(catAgg).join('g').attr('transform',(d,i)=>`translate(${(i%cols)*approxColWidth},${Math.floor(i/cols)*22})`).each(function(d){
    const g = d3.select(this);
    g.append('rect').attr('width',14).attr('height',14).attr('fill', colorForNodeObj({c:d.c})).attr('rx',2).attr('ry',2);
    g.append('text').attr('x',18).attr('y',12).attr('font-size','12px').attr('fill','#222').text(d=>`${d.c} ${ (d.open*100).toFixed(1) }%`);
  });
}
// ===== 4. HEATMAP MATRIX =====
function renderHeatmap(data, container) {
  // Aggregate by 学科大类 (category) and render category × category heatmap
  container.innerHTML = '';
  const disc = data.d, matrix = data.m, n = data.n;
  // build category list in original encounter order
  const categories = Array.from(new Set(disc.map(d => d.c || 'Other')));
  const k = categories.length;
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));

  // aggregate matrix into category × category, skipping discipline self-citations
  const catMatrix = Array.from({ length: k }, () => Array.from({ length: k }, () => 0));
  for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) {
    if (i === j) continue; // skip self-citation
    const vi = matrix[i] && matrix[i][j] ? matrix[i][j] : 0;
    if (!vi) continue;
    const ci = catIndex[disc[i].c || 'Other'];
    const cj = catIndex[disc[j].c || 'Other'];
    catMatrix[ci][cj] += vi;
  }

  // use categories as labels (objects with .n and .c so colorForNodeObj works)
  const catDisc = categories.map(c => ({ n: c, c: c }));
  const nCat = k;
  // Responsive cell size based on category count
  const cellSize = nCat <= 8 ? 48 : nCat <= 12 ? 36 : Math.max(12, Math.min(32, 700 / nCat));
  const hw = cellSize * nCat, hh = cellSize * nCat;
  // Margin computed from actual label lengths to avoid overlap
  const maxRowLabel = d3.max(disc, d => d.n.length) || 10;
  const maxColLabel = d3.max(disc, d => d.n.length) || 10;
  
  // 简化：不使用复杂的旋转计算，直接设置固定边距
  const margin = {
    top: Math.max(100, maxColLabel * 5),
    right: 30,
    bottom: 90,
    left: Math.max(300, maxRowLabel * 9)
  };
  const width = hw + margin.left + margin.right;
  const height = hh + margin.top + margin.bottom;

  // use colorForNodeObj for category/role swatches
  // Log(x+1) color scale �?smooth non-linear
  const maxVal = d3.max(catMatrix.flat()) || 1;
  const logMax = Math.log(maxVal + 1);
  const colorScale = v => {
    const t = Math.log(v + 1) / logMax;
    return d3.interpolateRgb('#f7f7f7', '#08306b')(Math.pow(t, 0.6));
  };

  const svg = d3.select(container).append('svg').attr('width', width).attr('height', height);
  const g = svg.append('g').attr('transform', `translate(${margin.left},${margin.top})`);

  // Row labels (source disciplines, right-aligned)
  g.selectAll('.hlr').data(catDisc).join('text').attr('class', 'heatmap-label')
    .attr('x', -30)
    .attr('y', (d, i) => i * cellSize + cellSize / 2)
    .attr('dy', '0.35em')
    .attr('text-anchor', 'end')
    .style('font-size', Math.min(9, cellSize * 0.32) + 'px')
    .style('fill', '#333')
    .text(d => d.n);

  // Column labels
  g.selectAll('.hlc').data(catDisc).join('text').attr('class', 'heatmap-label')
    .attr('x', (d, i) => i * cellSize + cellSize / 2)
    .attr('y', -14)
    .attr('dy', '0.35em')
    .attr('text-anchor', 'start')
    .attr('transform', (d, i) => `rotate(-60, ${i * cellSize + cellSize / 2}, -14)`)
    .style('font-size', Math.min(8, cellSize * 0.28) + 'px')
    .style('fill', '#333')
    .text(d => d.n);

  // Category color indicators
  g.selectAll('.cbr').data(catDisc).join('rect')
    .attr('x', -12)
    .attr('y', (d, i) => i * cellSize + 2)
    .attr('width', 4)
    .attr('height', cellSize - 4)
    .attr('fill', d => colorForNodeObj(d))
    .attr('rx', 1);
  g.selectAll('.cbc').data(catDisc).join('rect')
    .attr('x', (d, i) => i * cellSize + 2)
    .attr('y', -12)
    .attr('width', cellSize - 4)
    .attr('height', 4)
    .attr('fill', d => colorForNodeObj(d))
    .attr('ry', 1);

  // Cells (category aggregated)
  g.selectAll('.cell').data(d3.cross(d3.range(nCat), d3.range(nCat))).join('rect').attr('class', 'heatmap-cell')
    .attr('x', ([, j]) => j * cellSize)
    .attr('y', ([i]) => i * cellSize)
    .attr('width', cellSize)
    .attr('height', cellSize)
    .attr('fill', ([i, j]) => colorScale(catMatrix[i][j]))
    .attr('stroke', '#fff')
    .attr('stroke-width', 0.5)
    .on('mouseenter', function(ev, [i, j]) {
      d3.select(this).attr('stroke', '#e74c3c').attr('stroke-width', 2);
      showTT(ev.offsetX, ev.offsetY, `<div class="tt-title">${catDisc[i].n} → ${catDisc[j].n}</div><div class="tt-row"><span>流动</span><span>${catMatrix[i][j] ? catMatrix[i][j].toLocaleString() : '0'}</span></div>`);
    })
    .on('mouseleave', function() { 
      d3.select(this).attr('stroke', '#fff').attr('stroke-width', 0.5); 
      hideTT(); 
    });

  // Axis titles
  svg.append('text').attr('class', 'axis-label')
    .attr('x', margin.left + hw / 2)
    .attr('y', margin.top + hh + 28)
    .attr('text-anchor', 'middle')
    .attr('font-size', '11px')
    .attr('fill', '#888')
    .text('目标学科');
    
  svg.append('text').attr('class', 'axis-label')
    .attr('x', -(margin.top + hh / 2))
    .attr('y', 18)
    .attr('transform', 'rotate(-90)')
    .attr('text-anchor', 'middle')
    .attr('font-size', '11px')
    .attr('fill', '#888')
    .text('来源学科');

  // ===== 渐变色图例 =====
  const legWidth = 200;
  const legHeight = 12;
  const legX = margin.left + (hw - legWidth) / 2;  // 居中对齐
  const legY = margin.top + hh + 42;
  
  // 创建渐变
  const defs = svg.append('defs');
  const gradient = defs.append('linearGradient')
    .attr('id', 'heatmap-gradient')
    .attr('x1', '0%')
    .attr('y1', '0%')
    .attr('x2', '100%')
    .attr('y2', '0%');
  
  // 添加渐变节点
  [0, 0.2, 0.4, 0.6, 0.8, 1].forEach(p => {
    const color = d3.interpolateRgb('#f7f7f7', '#08306b')(Math.pow(p, 0.6));
    gradient.append('stop')
      .attr('offset', `${p * 100}%`)
      .attr('stop-color', color);
  });
  
  // 图例矩形
  svg.append('rect')
    .attr('x', legX)
    .attr('y', legY)
    .attr('width', legWidth)
    .attr('height', legHeight)
    .attr('fill', 'url(#heatmap-gradient)')
    .attr('rx', 2);
  
  // 图例刻度标签（手动添加）
  const legendLabels = [0, maxVal * 0.25, maxVal * 0.5, maxVal * 0.75, maxVal];
  const formatLegendValue = (val) => {
    if (!val) return '0';
    const wan = val / 10000;
    const rounded = Math.round(wan / 10) * 10;
    return `约${rounded}万`;
  };
  legendLabels.forEach((val, idx) => {
    const x = legX + (idx / (legendLabels.length - 1)) * legWidth;
    svg.append('text')
      .attr('x', x)
      .attr('y', legY + legHeight + 12)
      .attr('text-anchor', 'middle')
      .style('font-size', '9px')
      .style('fill', '#667085')
      .style('font-weight', '500')
      .text(formatLegendValue(val));
  });
  
  // 图例标题
  svg.append('text')
    .attr('x', legX + legWidth / 2)
    .attr('y', legY - 6)
    .attr('text-anchor', 'middle')
    .style('font-size', '10px')
    .style('fill', '#64748b')
    .style('font-weight', '600')
    .text('学科间流动量（约）');
}

// ===== 5. FOCUS SANKEY / RIVER VIEWS =====
// ===== 4.5 NETWORK (力导向图) =====
function renderNetwork(data, container) {
  const disc = data.d || [], matrix = data.m || [], n = data.n || 0;
  const totalN = disc.length;
  container.innerHTML = '';
  const width = Math.min(1200, Math.max(720, container.clientWidth || 900));
  const height = Math.max(520, Math.round(width * 0.58));
  const svg = d3.select(container).append('svg').attr('width', width).attr('height', height).style('display', 'block').style('margin', '0 auto');
  const g = svg.append('g').attr('class', 'network-layer');

  // aggregate to discipline categories
  const categories = Array.from(new Set(disc.map(d => d.c || 'Other')));
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));
  const k = categories.length;
  const catMatrix = Array.from({ length: k }, () => Array.from({ length: k }, () => 0));
  const catStats = categories.map(() => ({ o: 0, i: 0, s: 0 }));

  for (let i = 0; i < totalN; i++) {
    const ci = catIndex[disc[i].c || 'Other'];
    const self = disc[i].s || 0;
    // subtract discipline self-citation from category-level o/i
    catStats[ci].o += (disc[i].o || 0) - self;
    catStats[ci].i += (disc[i].i || 0) - self;
    catStats[ci].s += 0; // category self set to 0 since discipline self removed
    for (let j = 0; j < totalN; j++) {
      if (i === j) continue; // skip discipline self-citation
      const v = (matrix[i] && matrix[i][j]) ? matrix[i][j] : 0;
      if (!v) continue;
      const cj = catIndex[disc[j].c || 'Other'];
      catMatrix[ci][cj] += v;
    }
  }

  // nodes now represent categories
  const nodes = categories.map((c, i) => ({
    id: i,
    n: c,
    name: c,
    c,
    category: c,
    role: 'unknown',
    size: catStats[i].o + catStats[i].i + catStats[i].s
  }));

  // collect all directed edges (exclude self-loops)
  const allEdges = [];
  for (let i = 0; i < k; i++) for (let j = 0; j < k; j++) {
    if (i === j) continue;
    const v = catMatrix[i][j];
    if (v > 0) allEdges.push({ source: i, target: j, value: v });
  }

  // keep top edges to avoid clutter (heuristic)
  allEdges.sort((a, b) => b.value - a.value);
  const maxEdges = Math.max(30, Math.min(500, totalN * 6));
  const links = allEdges.slice(0, maxEdges);

  const nodeSizeScale = d3.scaleSqrt().domain([0, d3.max(nodes, d => d.size) || 1]).range([4, 20]);
  const linkWidthScale = d3.scaleSqrt().domain([0, d3.max(links, d => d.value) || 1]).range([0.6, 6]);

  // simulation
  const simulation = d3.forceSimulation(nodes)
    .force('link', d3.forceLink(links).id(d => d.id).distance(d => 80).strength(0.6))
    .force('charge', d3.forceManyBody().strength(-180))
    .force('center', d3.forceCenter(width / 2, height / 2))
    .force('collide', d3.forceCollide().radius(d => nodeSizeScale(d.size) + 6).iterations(1));

  // zoom
  svg.call(d3.zoom().on('zoom', (event) => { g.attr('transform', event.transform); }));

  // links
  const linkG = g.append('g').attr('class', 'network-links');
  const link = linkG.selectAll('path').data(links).join('path')
    .attr('fill', 'none')
    .attr('stroke', '#999')
    .attr('stroke-opacity', 0.35)
    .attr('stroke-width', d => Math.max(0.6, linkWidthScale(d.value)))
    .attr('marker-end', '');

  // nodes
  const nodeG = g.append('g').attr('class', 'network-nodes');
  const node = nodeG.selectAll('g').data(nodes).join('g').attr('class', 'node');

  node.append('circle')
    .attr('r', d => nodeSizeScale(d.size))
    .attr('fill', d => colorForNodeObj(d))
    .attr('stroke', 'rgba(0,0,0,0.12)')
    .attr('stroke-width', 0.8)
    .on('mouseenter', function(event, d) {
      d3.select(this).attr('stroke-width', 1.6);
      const info = catStats[d.id] || { o: 0, i: 0, s: 0 };
      const html = `<div class="tt-title">${d.name}</div><div class="tt-row"><span>流出</span><span>${(info.o||0).toLocaleString()}</span></div><div class="tt-row"><span>流入</span><span>${(info.i||0).toLocaleString()}</span></div><div class="tt-row"><span>自流</span><span>${(info.s||0).toLocaleString()}</span></div>`;
      showTT(event.offsetX, event.offsetY, html);
    })
    .on('mouseleave', function() { d3.select(this).attr('stroke-width', 0.8); hideTT(); });

  node.append('title').text(d => d.name);

  // labels (small)
  node.append('text')
    .attr('x', d => nodeSizeScale(d.size) + 6)
    .attr('y', 3)
    .attr('font-size', 11)
    .attr('fill', '#222')
    .text(d => d.name)
    .style('pointer-events', 'none');

  // dragging
  function drag(sim) {
    function dragstarted(event, d) {
      if (!event.active) sim.alphaTarget(0.3).restart();
      d.fx = d.x; d.fy = d.y;
    }
    function dragged(event, d) { d.fx = event.x; d.fy = event.y; }
    function dragended(event, d) {
      if (!event.active) sim.alphaTarget(0);
      d.fx = null; d.fy = null;
    }
    return d3.drag().on('start', dragstarted).on('drag', dragged).on('end', dragended);
  }
  node.call(drag(simulation));

  // link path generator for curved links
  function linkArc(d) {
    const dx = d.target.x - d.source.x, dy = d.target.y - d.source.y, dr = Math.sqrt(dx * dx + dy * dy);
    return `M${d.source.x},${d.source.y}A${dr},${dr} 0 0,1 ${d.target.x},${d.target.y}`;
  }

  simulation.on('tick', () => {
    link.attr('d', linkArc);
    node.attr('transform', d => `translate(${d.x},${d.y})`);
  });
  // stop any previous flow timer to avoid duplicates
  if (window._flowTimer) {
    try { window._flowTimer.stop(); } catch (e) {}
    window._flowTimer = null;
  }

  // particle flow animation along link paths
  try {
    if (links.length > 0) {
      const maxLinkVal = d3.max(links, d => d.value) || 1;
      const linkNodes = link.nodes();
      const particles = [];
      links.forEach((lk, idx) => {
        const pathNode = linkNodes[idx];
        if (!pathNode || typeof pathNode.getTotalLength !== 'function') return;
        const ratio = lk.value / maxLinkVal;
        const count = Math.max(1, Math.ceil(flowDensity * ratio * 3));
        for (let k = 0; k < count; k++) {
          const c = g.append('circle').attr('class', 'flow-dot').attr('r', Math.max(1.2, Math.min(3, nodeSizeScale(nodes[lk.source]?.size || 1) * 0.16))).attr('pointer-events', 'none');
          particles.push({ pathNode, t: Math.random(), speed: (0.2 + 0.8 * ratio) * flowSpeed, circle: c });
        }
      });

      let last = null;
      window._flowTimer = d3.timer((elapsed) => {
        if (!flowAnim) return;
        if (last === null) { last = elapsed; return; }
        const dt = (elapsed - last) / 1000; last = elapsed;
        particles.forEach(p => {
          try {
            const L = p.pathNode.getTotalLength();
            if (!L) return;
            p.t = (p.t + p.speed * dt) % 1;
            const pt = p.pathNode.getPointAtLength(p.t * L);
            p.circle.attr('cx', pt.x).attr('cy', pt.y);
          } catch (e) { /* ignore transient errors */ }
        });
      });
    }
  } catch (e) { console.warn('flow animation setup failed', e); }

  // simple legend: role or category
  const leg = document.getElementById('legend'); if (leg) leg.style.display = 'block';
}

function renderFocusSankey(mode) {
  // Use full (un-sliced) data for the selected period and merge analysis info
  const raw = FULLDATA.periods[currentPeriod];
  const data = { l: raw.l, d: (raw.d || []).map(dd => Object.assign({}, dd)), m: raw.m, n: (raw.d || []).length };
  data.d.forEach(dd => {
    const a = ANALYSIS_MAP[dd.n];
    if (a) {
      dd.role = a.role || 'unknown';
      dd.pagerank = a.pagerank || 0;
      dd.community = a.community || -1;
    } else {
      dd.role = 'unknown';
    }
  });
  const disc = data.d, matrix = data.m, n = data.n;
  const container = document.getElementById('chartArea');
  container.innerHTML = '';
  // sankey size
  const width = Math.min(1000, container.clientWidth ? container.clientWidth - 160 : 740);
  const height = Math.max(360, Math.min(520, Math.round(width * 0.48)));
  const legendReserve = 280; // keep right side clear for fixed legend panel
  const sankeyRight = Math.max(220, width - legendReserve);
  const svg = d3.select(container).append('svg').attr('width', width).attr('height', height).style('display', 'block').style('margin', '0 auto');
  // aggregate by category
  const categories = Array.from(new Set(disc.map(d => d.c || 'Other')));
  const k = categories.length;
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));
  const catMatrix = Array.from({ length: k }, () => Array.from({ length: k }, () => 0));
  for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) {
    if (i === j) continue; // skip discipline self-citation
    const v = (matrix[i] && matrix[i][j]) ? matrix[i][j] : 0;
    if (!v) continue;
    const ci = catIndex[disc[i].c || 'Other'];
    const cj = catIndex[disc[j].c || 'Other'];
    catMatrix[ci][cj] += v;
  }

  // compute in/out per category
  const catOut = catMatrix.map(row => row.reduce((a, b) => a + b, 0));
  const catIn = catMatrix.map((_, j) => catMatrix.reduce((s, row) => s + (row[j] || 0), 0));

  const topK = 10;
  let nodes = [], links = [];
  const catNames = categories;
  if (mode === 'outA') {
    // pick category with maximum outflow
    let outIdx = catOut.reduce((iMax, val, idx, arr) => val > arr[iMax] ? idx : iMax, 0);
    // collect destinations (exclude self)
    const dests = [];
    for (let j = 0; j < k; j++) {
      if (j === outIdx) continue;
      const v = catMatrix[outIdx][j] || 0;
      if (v > 0) dests.push({ j, v });
    }
    dests.sort((a, b) => b.v - a.v);
    const top = dests.slice(0, topK);
    nodes.push({ name: catNames[outIdx], c: catNames[outIdx] });
    top.forEach(d => nodes.push({ name: catNames[d.j], c: catNames[d.j] }));
    links = top.map((d, idx) => ({ source: 0, target: idx + 1, value: d.v }));
  } else if (mode === 'inB') {
    // pick category with maximum inflow
    let inIdx = catIn.reduce((iMax, val, idx, arr) => val > arr[iMax] ? idx : iMax, 0);
    const srcs = [];
    for (let i = 0; i < k; i++) {
      if (i === inIdx) continue;
      const v = catMatrix[i][inIdx] || 0;
      if (v > 0) srcs.push({ i, v });
    }
    srcs.sort((a, b) => b.v - a.v);
    const top = srcs.slice(0, topK);
    top.forEach(s => nodes.push({ name: catNames[s.i], c: catNames[s.i] }));
    nodes.push({ name: catNames[inIdx], c: catNames[inIdx] });
    links = top.map((s, idx) => ({ source: idx, target: nodes.length - 1, value: s.v }));
  } else {
    svg.append('text').attr('x', 20).attr('y', 30).text('未知专题视图');
    return;
  }

  const graph = { nodes: nodes.map(d => ({ name: d.name, c: d.c })), links: links.map(l => ({ source: l.source, target: l.target, value: l.value })) };
  const align = mode === 'outA' ? d3.sankeyLeft : d3.sankeyRight;
  const sankey = d3.sankey().nodeWidth(18).nodePadding(8).nodeAlign(align).extent([[1, 1], [sankeyRight, height - 1]]);
  sankey(graph);

  // draw links
  const linkG = svg.append('g').attr('class', 'sankey-links');
  linkG.selectAll('path').data(graph.links).join('path')
    .attr('d', d3.sankeyLinkHorizontal())
    .attr('fill', 'none')
    .attr('stroke', d => {
      // color by source (category or role)
      try { return d3.color(colorForNodeObj(d.source)).darker(0.5); } catch (e) { return '#999'; }
    })
    .attr('stroke-opacity', 0.6)
    .attr('stroke-width', d => Math.max(1, d.width))
    .on('mouseenter', function(ev, d) {
      const s = d.source.name, t = d.target.name, v = d.value || 0;
      showTT(ev.offsetX, ev.offsetY, `<div class="tt-title">${s} → ${t}</div><div class="tt-row"><span>流量</span><span>${v.toLocaleString()}</span></div>`);
      d3.select(this).attr('stroke-opacity', 1);
    })
    .on('mouseleave', function() { hideTT(); d3.select(this).attr('stroke-opacity', 0.6); });

  // draw nodes
  const nodeG = svg.append('g').attr('class', 'sankey-nodes');
  const node = nodeG.selectAll('g').data(graph.nodes).join('g').attr('transform', d => `translate(${d.x0},${d.y0})`);
  node.append('rect')
    .attr('height', d => Math.max(6, d.y1 - d.y0))
    .attr('width', d => Math.max(6, d.x1 - d.x0))
    .attr('fill', d => colorForNodeObj(d))
    .attr('stroke', 'rgba(0,0,0,0.15)')
    .attr('stroke-width', 0.6);
  node.append('text')
    .attr('x', d => (mode === 'outA' && d.x1 > sankeyRight - 40) ? -6 : (mode === 'outA' ? d.x1 - d.x0 + 6 : -6))
    .attr('text-anchor', d => (mode === 'outA' && d.x1 > sankeyRight - 40) ? 'end' : (mode === 'outA' ? 'start' : 'end'))
    .attr('y', d => (d.y1 - d.y0) / 2)
    .attr('dy', '0.32em')
    .attr('font-size', '11px')
    .attr('fill', '#333')
    .text(d => d.name);
}

// ===== 留守率环图 (学科大类) =====
function renderRetention(data, container) {
  container.innerHTML = '';
  const raw = FULLDATA.periods[currentPeriod];
  const discs = raw.d || [];
  const categories = (FULLDATA.cats || []).map(([name]) => name);
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));
  const k = categories.length;

  // Aggregate per-category
  const catStats = categories.map(c => ({ name: c, self: 0, out: 0, incoming: 0 }));
  discs.forEach(d => {
    const ci = catIndex[d.c || 'Other'];
    if (ci === undefined) return;
    catStats[ci].self += d.s || 0;
    catStats[ci].out += d.o || 0;
    catStats[ci].incoming += d.i || 0;
  });

  // Compute retention rate: self / (total outflow that includes self)
  catStats.forEach(cs => {
    cs.total = cs.out;
    cs.retentionRate = cs.total > 0 ? cs.self / cs.total : 0;
  });
  catStats.sort((a, b) => b.retentionRate - a.retentionRate);

  const width = Math.max(980, container.clientWidth || 980);
  const nCats = catStats.length;
  const cols = Math.min(nCats, Math.max(3, Math.floor(width / 210)));
  const cellW = Math.floor(width / cols);
  const outerR = Math.min(68, cellW * 0.4);
  const innerR = outerR * 0.58;
  const cellH = outerR * 2 + 48;
  const nRows = Math.ceil(nCats / cols);
  const height = nRows * cellH + 60;

  const svg = d3.select(container).append('svg')
    .attr('width', width).attr('height', height);

  const pie = d3.pie().value(d => d.value).sort(null);
  const arc = d3.arc().innerRadius(innerR).outerRadius(outerR);

  catStats.forEach((cs, idx) => {
    const col = idx % cols;
    const row = Math.floor(idx / cols);
    const cx = col * cellW + cellW / 2;
    const cy = row * cellH + outerR + 10;

    const g = svg.append('g').attr('transform', `translate(${cx},${cy})`);

    const pieData = pie([
      { name: 'cross', value: Math.max(0, cs.out - cs.self) },
      { name: 'self', value: cs.self },
    ]);

    g.selectAll('path').data(pieData).join('path')
      .attr('d', arc)
      .attr('fill', d => d.data.name === 'self' ? '#2ecc71' : '#3498db')
      .attr('opacity', 0.82)
      .attr('stroke', '#fff')
      .attr('stroke-width', 0.5);

    // Center text
    g.append('text')
      .attr('text-anchor', 'middle')
      .attr('dy', '-0.2em')
      .attr('font-size', Math.max(11, outerR * 0.32))
      .attr('font-weight', '700')
      .attr('fill', '#2ecc71')
      .text(d3.format('.0%')(cs.retentionRate));

    // Category name
    g.append('text')
      .attr('text-anchor', 'middle')
      .attr('y', outerR + 16)
      .attr('font-size', Math.max(9, outerR * 0.24))
      .attr('fill', '#555')
      .text(cs.name);

    g.on('mousemove', (event) =>
      showTT(event.clientX, event.clientY,
        `<div class="tt-title">${cs.name}</div>
         <div class="tt-row"><span>自引</span><span>${cs.self.toLocaleString()}</span></div>
         <div class="tt-row"><span>跨学科引用</span><span>${(cs.out - cs.self).toLocaleString()}</span></div>
         <div class="tt-row"><span>自引率</span><span>${d3.format('.1%')(cs.retentionRate)}</span></div>`))
      .on('mouseleave', hideTT);
  });

  // Legend
  const legX = 30;
  const legY = height - 22;
  const legG = svg.append('g').attr('transform', `translate(${legX},${legY})`);
  [{ lbl: '自引留存', c: '#2ecc71' }, { lbl: '跨学科流出', c: '#3498db' }].forEach((item, i) => {
    const lg = legG.append('g').attr('transform', `translate(${i * 120},0)`);
    lg.append('rect').attr('width', 10).attr('height', 10).attr('fill', item.c).attr('rx', 2);
    lg.append('text').attr('x', 15).attr('y', 9).attr('font-size', '11px').attr('fill', '#555').text(item.lbl);
  });

  svg.append('text')
    .attr('x', 30).attr('y', 22)
    .attr('font-size', '13px').attr('font-weight', '700').attr('fill', '#1f4f9a')
    .text(`学科大类留守率 — ${raw.l}`);
}

// ===== 弦图 (Chord Diagram) =====
function renderChord(data, container) {
  container.innerHTML = '';
  const raw = FULLDATA.periods[currentPeriod];
  const discs = raw.d || [];
  const categories = (FULLDATA.cats || []).map(([name]) => name);
  const nCats = categories.length;
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));

  // Aggregate discipline matrix to category matrix
  const catMatrix = Array.from({ length: nCats }, () => Array(nCats).fill(0));
  const m = raw.m || [];
  const n = discs.length;
  for (let i = 0; i < n; i++) {
    const ci = catIndex[discs[i].c || 'Other'];
    if (ci === undefined) continue;
    for (let j = 0; j < n; j++) {
      if (i === j) continue; // skip self-citation
      const v = (m[i] && m[i][j]) ? m[i][j] : 0;
      if (!v) continue;
      const cj = catIndex[discs[j].c || 'Other'];
      if (cj === undefined) continue;
      catMatrix[ci][cj] += v;
    }
  }

  const width = Math.min(960, Math.max(700, container.clientWidth || 900));
  const height = Math.max(600, Math.round(width * 0.78));
  const outerRadius = Math.min(width, height) * 0.42;
  const innerRadius = outerRadius * 0.88;

  const svg = d3.select(container).append('svg')
    .attr('width', width).attr('height', height)
    .append('g').attr('transform', `translate(${width / 2},${height / 2})`);

  const chordLayout = d3.chord()
    .padAngle(0.04)
    .sortSubgroups(d3.descending)
    .sortChords(d3.descending);
  const chords = chordLayout(catMatrix);

  const catColors = Object.fromEntries(FULLDATA.cats || []);

  // Compute group data from chords (D3 v7 stores angle info in chord endpoints)
  const groupData = categories.map((name, idx) => {
    let s0 = Infinity, s1 = -Infinity;
    chords.forEach(c => {
      if (c.source.index === idx) { if (c.source.startAngle < s0) s0 = c.source.startAngle; if (c.source.endAngle > s1) s1 = c.source.endAngle; }
      if (c.target.index === idx) { if (c.target.startAngle < s0) s0 = c.target.startAngle; if (c.target.endAngle > s1) s1 = c.target.endAngle; }
    });
    const totalOut = d3.sum(catMatrix[idx]);
    const totalIn = d3.sum(catMatrix.map(row => row[idx]));
    return { name, index: idx, startAngle: s0, endAngle: s1, value: totalOut + totalIn, totalOut, totalIn };
  });

  // Groups (outer arcs)
  const arcGen = d3.arc().innerRadius(innerRadius).outerRadius(outerRadius);

  const group = svg.append('g').selectAll('g').data(groupData).join('g');

  group.append('path')
    .attr('d', d => arcGen(d))
    .attr('fill', d => catColors[d.name] || '#999')
    .attr('stroke', '#fff')
    .attr('stroke-width', 1)
    .style('cursor', 'pointer')
    .on('mouseenter', function(ev, d) {
      d3.select(this).attr('opacity', 0.85);
      svg.selectAll('.chord-ribbon')
        .attr('opacity', rd => rd.source.index === d.index || rd.target.index === d.index ? 0.8 : 0.1);
    })
    .on('mouseleave', function() {
      d3.select(this).attr('opacity', 1);
      svg.selectAll('.chord-ribbon').attr('opacity', 0.55);
    })
    .on('mousemove', (event, d) =>
      showTT(event.clientX, event.clientY,
        `<div class="tt-title">${d.name}</div>
         <div class="tt-row"><span>流出</span><span>${d.totalOut.toLocaleString()}</span></div>
         <div class="tt-row"><span>流入</span><span>${d.totalIn.toLocaleString()}</span></div>`))
    .on('mouseleave', hideTT);

  // Labels on groups
  group.append('text')
    .each(d => { d.angle = (d.startAngle + d.endAngle) / 2; })
    .attr('dy', '0.35em')
    .attr('transform', d => {
      const a = d.angle * 180 / Math.PI - 90;
      const r = outerRadius + 18;
      const x = r * Math.cos(d.angle - Math.PI / 2);
      const y = r * Math.sin(d.angle - Math.PI / 2);
      return `translate(${x},${y}) rotate(${a})`;
    })
    .attr('text-anchor', d => d.angle > Math.PI ? 'end' : 'start')
    .attr('font-size', '11px')
    .attr('fill', '#333')
    .text(d => d.name);

  // Ribbons
  const ribbon = d3.ribbon().radius(innerRadius);
  svg.append('g')
    .selectAll('path')
    .data(chords)
    .join('path')
    .attr('class', 'chord-ribbon')
    .attr('d', ribbon)
    .attr('fill', d => catColors[categories[d.source.index]] || '#999')
    .attr('fill-opacity', 0.55)
    .attr('stroke', '#fff')
    .attr('stroke-width', 0.3)
    .on('mouseenter', function(ev, d) {
      d3.select(this).attr('fill-opacity', 0.9).attr('stroke-width', 1);
      svg.selectAll('.chord-ribbon')
        .filter(rd => rd !== d)
        .attr('opacity', 0.08);
    })
    .on('mouseleave', function() {
      d3.select(this).attr('fill-opacity', 0.55).attr('stroke-width', 0.3);
      svg.selectAll('.chord-ribbon').attr('opacity', 1);
    })
    .on('mousemove', (event, d) =>
      showTT(event.clientX, event.clientY,
        `<div class="tt-title">${categories[d.source.index]} → ${categories[d.target.index]}</div>
         <div class="tt-row"><span>流动次数</span><span>${d.source.value.toLocaleString()}</span></div>`))
    .on('mouseleave', hideTT);
}

// ===== 差异热力图 (学科大类, Early vs Late) =====
function renderDiffHeatmap(data, container) {
  container.innerHTML = '';
  const early = FULLDATA.periods.early;
  const late = FULLDATA.periods.late;
  if (!early || !late) return;

  const categories = (FULLDATA.cats || []).map(([name]) => name);
  const nCats = categories.length;
  const catIndex = Object.fromEntries(categories.map((c, i) => [c, i]));

  // Aggregate both periods to category level
  function aggregateCat(period) {
    const discs = period.d || [];
    const m = period.m || [];
    const n = discs.length;
    const cm = Array.from({ length: nCats }, () => Array(nCats).fill(0));
    for (let i = 0; i < n; i++) {
      const ci = catIndex[discs[i].c || 'Other'];
      if (ci === undefined) continue;
      for (let j = 0; j < n; j++) {
        if (i === j) continue;
        const v = (m[i] && m[i][j]) ? m[i][j] : 0;
        if (!v) continue;
        const cj = catIndex[discs[j].c || 'Other'];
        if (cj === undefined) continue;
        cm[ci][cj] += v;
      }
    }
    return cm;
  }

  const earlyM = aggregateCat(early);
  const lateM = aggregateCat(late);

  // Compute diff
  let maxAbs = 0;
  const diffM = Array.from({ length: nCats }, () => Array(nCats).fill(0));
  for (let i = 0; i < nCats; i++) {
    for (let j = 0; j < nCats; j++) {
      diffM[i][j] = lateM[i][j] - earlyM[i][j];
      if (Math.abs(diffM[i][j]) > maxAbs) maxAbs = Math.abs(diffM[i][j]);
    }
  }
  if (maxAbs === 0) maxAbs = 1;

  const cellSize = 48;
  const margin = { top: 100, right: 30, bottom: 80, left: 280 };
  const hw = cellSize * nCats;
  const hh = cellSize * nCats;
  const width = hw + margin.left + margin.right;
  const height = hh + margin.top + margin.bottom;

  const svg = d3.select(container).append('svg')
    .attr('width', width).attr('height', height);

  const g = svg.append('g').attr('transform', `translate(${margin.left},${margin.top})`);

  const colorScale = d3.scaleSequential(d3.interpolateRdBu)
    .domain([maxAbs, -maxAbs]); // reversed: blue = decrease, red = increase

  // Row labels
  g.selectAll('.hlr').data(categories).join('text')
    .attr('class', 'heatmap-label')
    .attr('x', -14).attr('y', (d, i) => i * cellSize + cellSize / 2)
    .attr('dy', '0.35em').attr('text-anchor', 'end')
    .style('font-size', '11px').style('fill', '#333').text(d => d);

  // Column labels
  g.selectAll('.hlc').data(categories).join('text')
    .attr('class', 'heatmap-label')
    .attr('x', (d, i) => i * cellSize + cellSize / 2).attr('y', -14)
    .attr('dy', '0.35em').attr('text-anchor', 'start')
    .attr('transform', (d, i) => `rotate(-60, ${i * cellSize + cellSize / 2}, -14)`)
    .style('font-size', '10px').style('fill', '#333').text(d => d);

  // Cells
  const cells = [];
  for (let i = 0; i < nCats; i++) {
    for (let j = 0; j < nCats; j++) {
      cells.push({ i, j, diff: diffM[i][j], early: earlyM[i][j], late: lateM[i][j] });
    }
  }

  g.selectAll('.cell').data(cells).join('rect')
    .attr('class', 'heatmap-cell')
    .attr('x', d => d.j * cellSize).attr('y', d => d.i * cellSize)
    .attr('width', cellSize).attr('height', cellSize)
    .attr('fill', d => colorScale(d.diff))
    .attr('stroke', '#fff').attr('stroke-width', 0.5)
    .on('mouseenter', function(ev, d) {
      d3.select(this).attr('stroke', '#333').attr('stroke-width', 2);
      const changePct = d.early > 0 ? ((d.diff / d.early) * 100).toFixed(1) : 'N/A';
      showTT(ev.offsetX, ev.offsetY,
        `<div class="tt-title">${categories[d.i]} → ${categories[d.j]}</div>
         <div class="tt-row"><span>2009-2013</span><span>${d.early.toLocaleString()}</span></div>
         <div class="tt-row"><span>2014-2018</span><span>${d.late.toLocaleString()}</span></div>
         <div class="tt-row"><span>变化</span><span>${d.diff > 0 ? '+' : ''}${d.diff.toLocaleString()} (${changePct}%)</span></div>`);
    })
    .on('mouseleave', function() {
      d3.select(this).attr('stroke', '#fff').attr('stroke-width', 0.5);
      hideTT();
    });

  // Gradient legend
  const legW = 240;
  const legH = 14;
  const legX = margin.left + (hw - legW) / 2;
  const legY = margin.top + hh + 24;
  const defs = svg.append('defs');
  const grad = defs.append('linearGradient').attr('id', 'diffHeatLegend')
    .attr('x1', '0%').attr('x2', '100%').attr('y1', '0%').attr('y2', '0%');
  grad.append('stop').attr('offset', '0%').attr('stop-color', d3.interpolateRdBu(0));
  grad.append('stop').attr('offset', '50%').attr('stop-color', d3.interpolateRdBu(0.5));
  grad.append('stop').attr('offset', '100%').attr('stop-color', d3.interpolateRdBu(1));

  svg.append('rect')
    .attr('x', legX).attr('y', legY)
    .attr('width', legW).attr('height', legH)
    .attr('fill', 'url(#diffHeatLegend)').attr('rx', 2);

  [-maxAbs, 0, maxAbs].forEach((v, idx) => {
    const tx = legX + (idx / 2) * legW;
    svg.append('text').attr('x', tx).attr('y', legY + legH + 14)
      .attr('text-anchor', 'middle').style('font-size', '10px').style('fill', '#667085')
      .text(v > 0 ? `+${(v / 1000).toFixed(0)}k` : v < 0 ? `${(v / 1000).toFixed(0)}k` : '0');
  });

  svg.append('text')
    .attr('x', legX + legW / 2).attr('y', legY - 8)
    .attr('text-anchor', 'middle').style('font-size', '11px').style('fill', '#64748b').style('font-weight', '600')
    .text('流动变化 (2014-2018 — 2009-2013)');
}
